package com.lightevents.events;
import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="ticket_lookup_codes")
public class TicketLookupCode { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String email; private String destination; private String channel; private String code; private Instant expiresAt; public Long getId(){return id;} public String getEmail(){return email;} public void setEmail(String v){email=v;} public String getDestination(){return destination;} public void setDestination(String v){destination=v;} public String getChannel(){return channel;} public void setChannel(String v){channel=v;} public String getCode(){return code;} public void setCode(String v){code=v;} public Instant getExpiresAt(){return expiresAt;} public void setExpiresAt(Instant v){expiresAt=v;} }
